# Security Audit Report: Node.js Express Application

## Executive Summary
This application contains **critical security vulnerabilities** that could lead to complete system compromise, data exfiltration, and denial of service. Immediate remediation is required.

---

## Vulnerability Analysis

### 1. **Hardcoded Credentials** (Critical Severity)
**Location:** `/login` endpoint
**Issue:** Default admin credentials (`admin/admin123`) are hardcoded in source code.
**Risk:** 
- Unauthorized access to admin functionality
- Credential exposure in version control systems
- Brute force attacks with known credentials

**Impact:** Full system compromise, data theft, unauthorized configuration changes

**Fix:**
```javascript
// Use environment variables or secure credential storage
const adminUser = process.env.ADMIN_USERNAME;
const adminPass = process.env.ADMIN_PASSWORD;

// Implement proper password hashing with bcrypt
const bcrypt = require('bcrypt');
const SALT_ROUNDS = 12;

app.post('/login', async (req, res) => {
  const {username, password} = req.body;
  try {
    const user = await db.findUser(username);
    if (!user) {
      return res.status(401).json({error: 'Invalid credentials'});
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);
    if (!validPassword) {
      return res.status(401).json({error: 'Invalid credentials'});
    }

    // Generate secure token
    const token = crypto.randomBytes(32).toString('hex');
    sessions[token] = {username, expiresAt: Date.now() + 3600000};
    res.json({token});
  } catch (error) {
    res.status(500).json({error: 'Authentication failed'});
  }
});
```

---

### 2. **Command Injection** (Critical Severity)
**Location:** `/admin/users` endpoint
**Issue:** `execSync('cat /etc/passwd')` without any input validation or sanitization.
**Risk:** 
- Arbitrary command execution
- System compromise
- Data exfiltration
- Lateral movement

**Impact:** Complete server compromise, data theft, potential botnet participation

**Fix:**
```javascript
// Option 1: Remove dangerous functionality
app.get('/admin/users', (req, res) => {
  if (!req.user || req.user.role !== 'admin') {
    return res.status(403).json({error: 'Forbidden'});
  }

  // Use safe database query instead
  res.json({users: db.getAllUsers()});
});

// Option 2: If file reading is necessary, use safe methods
const fs = require('fs').promises;
const path = require('path');

app.get('/admin/users', async (req, res) => {
  if (!req.user || req.user.role !== 'admin') {
    return res.status(403).json({error: 'Forbidden'});
  }

  try {
    const filePath = path.join(__dirname, 'users.json');
    const data = await fs.readFile(filePath, 'utf8');
    res.send(data);
  } catch (error) {
    res.status(500).json({error: 'File not found'});
  }
});
```

---

### 3. **Path Traversal / Arbitrary File Write** (Critical Severity)
**Location:** `/upload` endpoint
**Issue:** No validation of `filename` parameter, allowing arbitrary file system writes.
**Risk:** 
- Overwriting critical system files
- Uploading malicious scripts (PHP, JS, etc.)
- Denial of service
- Remote code execution

**Impact:** Complete server compromise, data loss, persistence mechanisms

**Fix:**
```javascript
const path = require('path');
const crypto = require('crypto');

app.post('/upload', (req, res) => {
  if (!req.body.filename || !req.body.data) {
    return res.status(400).json({error: 'Missing required fields'});
  }

  // Validate and sanitize filename
  const originalFilename = req.body.filename;
  const safeFilename = path.basename(originalFilename); // Remove path components

  // Enforce file extension whitelist
  const allowedExtensions = ['.txt', '.json', '.csv'];
  const fileExtension = path.extname(safeFilename);

  if (!allowedExtensions.includes(fileExtension)) {
    return res.status(400).json({error: 'Invalid file type'});
  }

  // Generate secure filename with hash
  const fileHash = crypto.createHash('sha256').update(safeFilename).digest('hex');
  const newFilename = `${fileHash}${fileExtension}`;

  const uploadDir = path.join(__dirname, 'uploads');
  const filePath = path.join(uploadDir, newFilename);

  // Ensure upload directory exists
  const fs = require('fs');
  if (!fs.existsSync(uploadDir)) {
    fs.mkdirSync(uploadDir, {recursive: true});
  }

  try {
    fs.writeFileSync(filePath, req.body.data);
    res.json({status: 'ok', filename: newFilename});
  } catch (error) {
    res.status(500).json({error: 'Upload failed'});
  }
});
```

---

### 4. **Insecure Session Management** (High Severity)
**Location:** Session storage
**Issue:** 
- Random token generation using `Math.random()` (cryptographically weak)
- No token expiration
- No session validation
- Sessions stored in memory without cleanup

**Risk:** 
- Token prediction and forgery
- Session hijacking
- Memory exhaustion attacks
- No logout functionality

**Impact:** Unauthorized access, session takeover, DoS attacks

**Fix:**
```javascript
const crypto = require('crypto');
const jwt = require('jsonwebtoken');

// Use cryptographically secure token generation
const sessions = new Map();

app.post('/login', async (req, res) => {
  const {username, password} = req.body;

  try {
    // Validate credentials...

    // Generate secure JWT token
    const token = jwt.sign(
      {username, iat: Math.floor(Date.now() / 1000)},
      process.env.JWT_SECRET,
      {expiresIn: '1h'}
    );

    res.json({token, expiresIn: 3600});
  } catch (error) {
    res.status(500).json({error: 'Authentication failed'});
  }
});

// Add token validation middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({error: 'No token provided'});
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({error: 'Invalid token'});
    }
    req.user = user;
    next();
  });
};

// Use authenticated routes
app.get('/admin/users', authenticateToken, (req, res) => {
  // Admin-specific logic
});
```

---

### 5. **Missing Input Validation** (High Severity)
**Location:** All endpoints
**Issue:** No input validation or sanitization for any request parameters.
**Risk:** 
- Injection attacks (SQL, NoSQL, command)
- Malformed data causing errors
- Denial of service

**Fix:**
```javascript
const expressValidator = require('express-validator');
const { body, param, validationResult } = require('express-validator');

app.post('/login', [
  body('username').trim().notEmpty().isLength({max: 50}),
  body('password').trim().notEmpty().isLength({min: 8, max: 100})
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({errors: errors.array()});
  }
  // Continue with authentication logic
});

app.post('/upload', [
  body('filename').trim().notEmpty().isLength({max: 255}),
  body('data').trim().notEmpty()
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({errors: errors.array()});
  }
  // Continue with upload logic
});
```

---

### 6. **Missing Authentication/Authorization** (High Severity)
**Location:** `/admin/users` endpoint
**Issue:** No authentication or role-based access control.
**Risk:** 
- Unauthorized access to sensitive data
- Privilege escalation
- Data exposure

**Fix:**
```javascript
// Implement role-based access control
const authorize = (...roles) => {
  return (req, res, next) => {
    if (!req.user || !roles.includes(req.user.role)) {
      return res.status(403).json({error: 'Access denied'});
    }
    next();
  };
};

app.get('/admin/users', authenticateToken, authorize('admin'), (req, res) => {
  // Admin-only logic
});
```

---

### 7. **No Error Handling** (Medium Severity)
**Location:** All endpoints
**Issue:** No try-catch blocks, no error logging.
**Risk:** 
- Information disclosure through error messages
- Application crashes
- Poor debugging experience

**Fix:**
```javascript
// Global error handler
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({error: 'Something went wrong!'});
});

// Add logging middleware
const morgan = require('morgan');
app.use(morgan('combined'));
```

---

### 8. **Missing Security Headers** (Medium Severity)
**Issue:** No security headers configured.
**Risk:** 
- XSS attacks
- Clickjacking
- MIME type sniffing

**Fix:**
```javascript
const helmet = require('helmet');
app.use(helmet());

// Additional headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});
```

